import{_ as t,o as s,c as a,ag as r}from"./chunks/framework.B3IQijK_.js";const u=JSON.parse('{"title":"Investor","description":"Long-term, fundamentals-first research persona for Indian equities. Discover, analyze, value, compare, review results, test theses.","frontmatter":{"title":"Investor","description":"Long-term, fundamentals-first research persona for Indian equities. Discover, analyze, value, compare, review results, test theses.","outline":2,"head":[["link",{"rel":"canonical","href":"https://tradecli.in/wiki/guides/investor"}]]},"headers":[],"relativePath":"guides/investor.md","filePath":"guides/investor.md"}'),n={name:"guides/investor.md"};function i(o,e,l,d,c,h){return s(),a("div",null,[...e[0]||(e[0]=[r(`<h1 id="investor" tabindex="-1">Investor <a class="header-anchor" href="#investor" aria-label="Permalink to &quot;Investor&quot;">​</a></h1><p>Long-term, fundamentals-first research on Indian equities. Investor is built around the investing job: <strong>discover, analyze, value, compare, review results, test a thesis</strong>.</p><h2 id="what-it-s-for" tabindex="-1">What it&#39;s for <a class="header-anchor" href="#what-it-s-for" aria-label="Permalink to &quot;What it&#39;s for&quot;">​</a></h2><ul><li>Stock discovery using clear filters and investing styles: quality, value, growth, and dividend</li><li>Business quality, earnings trend, capital allocation, balance-sheet strength</li><li>Valuation using DCF where it fits, peer multiples otherwise</li><li>Post-results reviews, peer comparisons, and thesis re-checks</li><li>Held-stock reviews that include broker context when you already own the company</li></ul><p>Investor is not a generic market chat mode. It routes your request into a workflow and keeps the answer focused on evidence, trade-offs, and what changed.</p><h2 id="core-workflows" tabindex="-1">Core workflows <a class="header-anchor" href="#core-workflows" aria-label="Permalink to &quot;Core workflows&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Workflow</th><th>Use it for</th></tr></thead><tbody><tr><td>Find stocks</td><td>Discover Indian equities using Screener filters and investing styles</td></tr><tr><td>Deep stock analysis</td><td>Understand a company, business quality, financial trend, risks, and valuation context</td></tr><tr><td>DCF valuation</td><td>Estimate intrinsic value where cash-flow valuation makes sense</td></tr><tr><td>Results review</td><td>Check what changed after quarterly or annual results</td></tr><tr><td>Peer compare</td><td>Compare a company with listed peers on quality, growth, margins, and valuation</td></tr><tr><td>Thesis check</td><td>Test whether your original investing thesis still holds</td></tr></tbody></table><p>Discovery can be broad (&quot;find quality compounders&quot;) or style-specific (&quot;find dividend stocks with low debt&quot;). Analysis and valuation are company-first. Held-stock review uses broker context more heavily so Investor can tell whether the question is about a new idea or something already in your portfolio.</p><h2 id="primary-tools" tabindex="-1">Primary tools <a class="header-anchor" href="#primary-tools" aria-label="Permalink to &quot;Primary tools&quot;">​</a></h2><ul><li><a href="https://www.screener.in" target="_blank" rel="noreferrer">Screener.in</a> for discovery filters, fundamentals, peer metrics, annual trends, and quarterly trends</li><li>Groww and Kite MCP tools for current price, holdings context, quote sanity checks, and whether you already own the stock</li><li>News for recent company or sector developments</li><li>Browser as a last resort or when you explicitly ask Investor to navigate a website</li></ul><p>Investor is Screener-first for discovery, analysis, and valuation. Broker tools matter most when the question touches your current holdings, prices, margins, or portfolio context.</p><h2 id="typical-prompts" tabindex="-1">Typical prompts <a class="header-anchor" href="#typical-prompts" aria-label="Permalink to &quot;Typical prompts&quot;">​</a></h2><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Find quality compounders with ROCE &gt; 18% and D/E &lt; 0.5</span></span>
<span class="line"><span>Find dividend stocks with low debt and stable cash flows</span></span>
<span class="line"><span>Deep-dive Asian Paints</span></span>
<span class="line"><span>What&#39;s a reasonable intrinsic value for HDFC Life?</span></span>
<span class="line"><span>Compare INFY vs TCS vs HCLTECH on margins and growth</span></span>
<span class="line"><span>Q3 results review for Tata Motors — what changed?</span></span>
<span class="line"><span>Does my ITC thesis still hold?</span></span>
<span class="line"><span>Review my held stocks and flag where the thesis looks weaker</span></span></code></pre></div><div class="warning custom-block"><p class="custom-block-title">DCF exclusions</p><p>Investor does not run DCF on banks, NBFCs, insurers, or early-stage businesses. For those, it uses peer multiples and earnings trend instead.</p></div><h2 id="what-s-next" tabindex="-1">What&#39;s next <a class="header-anchor" href="#what-s-next" aria-label="Permalink to &quot;What&#39;s next&quot;">​</a></h2><ul><li><strong>Compare with other personas</strong> → <a href="/trading-sandbox-website-preview/wiki/guides/personas">Personas &amp; Modes</a></li><li><strong>Connect a broker for held-stock context</strong> → <a href="./../getting-started/broker-setup">Broker Setup</a></li></ul>`,16)])])}const v=t(n,[["render",i]]);export{u as __pageData,v as default};
